     1→import Router from '@koa/router';
     2→import { randomBytes, randomUUID } from 'node:crypto';
     3→import type { BridgeConfig } from '../config.js';
     4→import type { StateStore, ClientRegistrationRecord } from '../state/state-store.js';
     5→import { RegistrationTokenStore } from '../registration-token-store.js';
     6→import { createDcrAuthMiddleware } from '../middleware/dcr-auth.js';
     7→
     8→interface RegisterRouterDeps {
     9→  config: BridgeConfig;
    10→  stateStore: StateStore;
    11→  registrationTokenStore: RegistrationTokenStore;
    12→}
    13→
    14→interface RegistrationRequest {
    15→  redirect_uris?: unknown;
    16→  token_endpoint_auth_method?: unknown;
    17→  client_name?: unknown;
    18→  scope?: unknown;
    19→}
    20→
    21→const TOKEN_AUTH_METHODS = ['none', 'client_secret_post', 'client_secret_basic'] as const;
    22→type TokenEndpointAuthMethod = typeof TOKEN_AUTH_METHODS[number];
    23→
    24→function generateClientSecret(): string {
    25→  return randomBytes(48).toString('base64url');
    26→}
    27→
    28→export function createRegisterRouter({ config, stateStore, registrationTokenStore }: RegisterRouterDeps) {
    29→  const router = new Router();
    30→  const dcrAuth = createDcrAuthMiddleware(registrationTokenStore);
    31→
    32→  router.post('/register', async (ctx) => {
    33→    const body = ctx.request.body as RegistrationRequest;
    34→
    35→    const tokenEndpointAuthMethod = parseTokenEndpointAuthMethod(body.token_endpoint_auth_method);
    36→
    37→    const validationError = validateRegistrationRequest(body, config.redirectUris, tokenEndpointAuthMethod);
    38→    if (validationError) {
    39→      ctx.logger.warn({ error: validationError.body.error, description: validationError.body.error_description }, 'Client registration validation failed');
    40→      ctx.status = validationError.status;
    41→      ctx.body = validationError.body;
    42→      return;
    43→    }
    44→
    45→    // tokenEndpointAuthMethod is guaranteed to be non-null when validation passes
    46→    const authMethod = tokenEndpointAuthMethod!;
    47→    const redirectUris = (body.redirect_uris as string[]).map((uri) => uri.trim());
    48→    const scope = typeof body.scope === 'string' ? body.scope : undefined;
    49→    const clientName = typeof body.client_name === 'string' ? body.client_name : undefined;
    50→    const clientSecret = authMethod === 'none' ? undefined : generateClientSecret();
    51→
    52→    const clientId = randomUUID();
    53→    const issuedAt = Math.floor(Date.now() / 1000);
    54→
    55→    // Generate secure registration access token using the new token store
    56→    // The plaintext token is returned only once; only its hash is stored
    57→    let registrationAccessToken: string;
    58→    let registrationAccessTokenExpiresAt: number;
    59→    try {
    60→      const tokenResult = await registrationTokenStore.createToken(clientId);
    61→      registrationAccessToken = tokenResult.token;
    62→      registrationAccessTokenExpiresAt = Math.floor(tokenResult.expiresAt / 1000); // Convert to seconds
    63→    } catch (error) {
    64→      ctx.logger.error({ error: error instanceof Error ? error.message : String(error) }, 'Failed to create registration access token');
    65→      ctx.status = 500;
    66→      ctx.body = {
    67→        error: 'server_error',
    68→        error_description: 'Failed to create registration access token'
    69→      };
    70→      return;
    71→    }
    72→
    73→    const clientRecord: ClientRegistrationRecord = {
    74→      clientId,
    75→      tokenEndpointAuthMethod: authMethod,
    76→      clientSecret,
    77→      redirectUris,
    78→      scope,
    79→      clientName,
    80→      // Note: We no longer store the plaintext token in the client record
    81→      // The registrationAccessToken field now stores a placeholder indicating
    82→      // the token is managed by RegistrationTokenStore
    83→      registrationAccessToken: '[HASHED]',
    84→      registrationClientUri: `${config.bridge.baseUrl}/register/${clientId}`,
    85→      clientIdIssuedAt: issuedAt,
    86→      clientSecretExpiresAt: 0,
    87→      metadata: {
    88→        token_endpoint_auth_method: tokenEndpointAuthMethod
    89→      }
    90→    };
    91→
    92→    try {
    93→      await stateStore.storeClientRegistration(clientRecord);
    94→    } catch (error) {
    95→      // Clean up the token if client registration fails
    96→      await registrationTokenStore.deleteToken(clientId).catch(() => {});
    97→      ctx.logger.error({ error: error instanceof Error ? error.message : String(error) }, 'Failed to persist client registration');
    98→      ctx.status = 500;
    99→      ctx.body = {
   100→        error: 'server_error',
   101→        error_description: 'Failed to persist client registration'
   102→      };
   103→      return;
   104→    }
   105→
   106→    ctx.logger.info({ clientId, redirectUrisCount: redirectUris.length }, 'Client registration created');
   107→
   108→    ctx.status = 201;
   109→    ctx.body = buildClientRegistrationResponse(clientRecord, {
   110→      includeRegistrationAccessToken: true,
   111→      includeClientSecret: true,
   112→      registrationAccessToken,
   113→      registrationAccessTokenExpiresAt
   114→    });
   115→  });
   116→
   117→  // GET /register/:clientId - Protected by dcrAuth middleware
   118→  router.get('/register/:clientId', dcrAuth, async (ctx) => {
   119→    const clientId = ctx.params.clientId;
   120→
   121→    let record: ClientRegistrationRecord | null;
   122→    try {
   123→      record = await stateStore.getClientRegistration(clientId);
   124→    } catch (error) {
   125→      ctx.logger.error({ error: error instanceof Error ? error.message : String(error), clientId }, 'Failed to load client registration');
   126→      ctx.status = 500;
   127→      ctx.body = {
   128→        error: 'server_error',
   129→        error_description: 'Failed to load client registration'
   130→      };
   131→      return;
   132→    }
   133→
   134→    if (!record) {
   135→      ctx.status = 404;
   136→      ctx.body = {
   137→        error: 'not_found',
   138→        error_description: 'Client registration not found'
   139→      };
   140→      return;
   141→    }
   142→
   143→    // Token is already validated by middleware
   144→    // Note: We don't return the registration_access_token on GET requests
   145→    // per RFC 7592 Section 2.1 - token is only shown on initial registration
   146→    ctx.body = buildClientRegistrationResponse(record, {
   147→      includeRegistrationAccessToken: false,
   148→      includeClientSecret: true
   149→    });
   150→  });
   151→
   152→  // DELETE /register/:clientId - Protected by dcrAuth middleware
   153→  router.delete('/register/:clientId', dcrAuth, async (ctx) => {
   154→    const clientId = ctx.params.clientId;
   155→
   156→    let record: ClientRegistrationRecord | null;
   157→    try {
   158→      record = await stateStore.getClientRegistration(clientId);
   159→    } catch (error) {
   160→      ctx.logger.error({ error: error instanceof Error ? error.message : String(error), clientId }, 'Failed to load client registration for deletion');
   161→      ctx.status = 500;
   162→      ctx.body = {
   163→        error: 'server_error',
   164→        error_description: 'Failed to load client registration'
   165→      };
   166→      return;
   167→    }
   168→
   169→    if (!record) {
   170→      ctx.status = 404;
   171→      ctx.body = {
   172→        error: 'not_found',
   173→        error_description: 'Client registration not found'
   174→      };
   175→      return;
   176→    }
   177→
   178→    // Token is already validated by middleware
   179→    // Delete both the client registration and the token
   180→    try {
   181→      await Promise.all([
   182→        stateStore.deleteClientRegistration(clientId),
   183→        registrationTokenStore.deleteToken(clientId)
   184→      ]);
   185→    } catch (error) {
   186→      ctx.logger.error({ error: error instanceof Error ? error.message : String(error), clientId }, 'Failed to delete client registration');
   187→      ctx.status = 500;
   188→      ctx.body = {
   189→        error: 'server_error',
   190→        error_description: 'Failed to delete client registration'
   191→      };
   192→      return;
   193→    }
   194→
   195→    ctx.logger.info({ clientId }, 'Client registration deleted');
   196→
   197→    ctx.status = 204;
   198→  });
   199→
   200→  return router;
   201→}
   202→
   203→function validateRegistrationRequest(
   204→  body: RegistrationRequest,
   205→  _allowedRedirectUris: string[], // Unused - DCR accepts ANY redirect_uri
   206→  parsedMethod: TokenEndpointAuthMethod | null
   207→):
   208→  { status: number; body: Record<string, string> } | null {
   209→  if (!body.redirect_uris || !Array.isArray(body.redirect_uris) || body.redirect_uris.length === 0) {
   210→    return {
   211→      status: 400,
   212→      body: {
   213→        error: 'invalid_client_metadata',
   214→        error_description: 'redirect_uris must be a non-empty array'
   215→      }
   216→    };
   217→  }
   218→
   219→  // DCR accepts ANY redirect_uri - this is the whole point!
   220→  // Mittwald's redirect list is immutable, so we use DCR to allow clients
   221→  // to register their own redirect URIs with our bridge.
   222→  // The authorize endpoint validates against these DCR-registered URIs.
   223→  const redirectUris = body.redirect_uris as unknown[];
   224→  for (const uri of redirectUris) {
   225→    if (typeof uri !== 'string') {
   226→      return {
   227→        status: 400,
   228→        body: {
   229→          error: 'invalid_client_metadata',
   230→          error_description: 'redirect_uris must contain strings only'
   231→        }
   232→      };
   233→    }
   234→    // Validate URI format only, not against an allowlist
   235→    try {
   236→      new URL(uri);
   237→    } catch {
   238→      return {
   239→        status: 400,
