     2→import { randomUUID, randomBytes, createHash } from 'node:crypto';
     3→import type { BridgeConfig } from '../config.js';
     4→import type { StateStore } from '../state/state-store.js';
     5→
     6→/**
     7→ * Generates a cryptographically random code_verifier for PKCE.
     8→ * Per RFC 7636 Section 4.1: 43-128 characters, base64url alphabet.
     9→ * We generate 64 characters (48 bytes base64url encoded).
    10→ */
    11→function generateCodeVerifier(): string {
    12→  // 48 bytes = 64 base64url characters (after removing padding)
    13→  return randomBytes(48)
    14→    .toString('base64')
    15→    .replace(/\+/g, '-')
    16→    .replace(/\//g, '_')
    17→    .replace(/=+$/, '');
    18→}
    19→
    20→/**
    21→ * Computes code_challenge from code_verifier using S256 method.
    22→ * Per RFC 7636: code_challenge = BASE64URL(SHA256(code_verifier))
    23→ */
    24→function computeCodeChallenge(verifier: string): string {
    25→  return createHash('sha256')
    26→    .update(verifier)
    27→    .digest()
    28→    .toString('base64')
    29→    .replace(/\+/g, '-')
    30→    .replace(/\//g, '_')
    31→    .replace(/=+$/, '');
    32→}
    33→import {
    34→  DEFAULT_SCOPES,
    35→  MITTWALD_SCOPE_STRING,
    36→  buildScopeString,
    37→  validateRequestedScopes
    38→} from '../config/mittwald-scopes.js';
    39→
    40→interface AuthorizeRouterDeps {
    41→  config: BridgeConfig;
    42→  stateStore: StateStore;
    43→}
    44→
    45→export function createAuthorizeRouter({ config, stateStore }: AuthorizeRouterDeps) {
    46→  const router = new Router();
    47→
    48→  router.get('/authorize', async (ctx) => {
    49→    const {
    50→      response_type: responseType,
    51→      client_id: clientId,
    52→      redirect_uri: redirectUri,
    53→      scope = '',
    54→      state,
    55→      code_challenge: codeChallenge,
    56→      code_challenge_method: codeChallengeMethod,
    57→      resource
    58→    } = ctx.query as Record<string, string | undefined>;
    59→
    60→    ctx.logger.debug({
    61→      clientId,
    62→      redirectUri,
    63→      scope,
    64→      state: state ? `${state.substring(0, 8)}...` : undefined,
    65→      responseType,
    66→      codeChallenge: codeChallenge ? 'present' : 'missing',
    67→      resource
    68→    }, 'Incoming authorization request');
    69→
    70→    // Validate basic request parameters first
    71→    const basicError = validateBasicRequest({ responseType, clientId, redirectUri, state, codeChallenge, codeChallengeMethod });
    72→    if (basicError) {
    73→      ctx.logger.warn({ error: basicError.error, description: basicError.error_description, clientId, redirectUri }, 'Authorization request validation failed');
    74→      ctx.status = 400;
    75→      ctx.body = basicError;
    76→      return;
    77→    }
    78→
    79→    // Look up DCR-registered client to validate redirect_uri
    80→    // This is critical: Mittwald's redirect list is IMMUTABLE, so we use DCR
    81→    // to allow clients to register their own redirect URIs with our bridge
    82→    let clientRegistration;
    83→    try {
    84→      clientRegistration = await stateStore.getClientRegistration(clientId!);
    85→    } catch (err) {
    86→      ctx.logger.error({ error: err instanceof Error ? err.message : String(err), clientId }, 'Failed to load client registration');
    87→      ctx.status = 500;
    88→      ctx.body = { error: 'server_error', error_description: 'Failed to load client registration' };
    89→      return;
    90→    }
    91→
    92→    if (!clientRegistration) {
    93→      ctx.logger.warn({ clientId }, 'Authorization request for unregistered client - must use DCR first');
    94→      ctx.status = 400;
    95→      ctx.body = { error: 'invalid_client', error_description: 'Client not registered. Use Dynamic Client Registration (POST /register) first.' };
    96→      return;
    97→    }
    98→
    99→    // Validate redirect_uri against DCR-registered URIs
   100→    if (!clientRegistration.redirectUris.includes(redirectUri!)) {
   101→      ctx.logger.warn({ clientId, redirectUri, registeredUris: clientRegistration.redirectUris }, 'redirect_uri not in DCR-registered list');
   102→      ctx.status = 400;
   103→      ctx.body = { error: 'invalid_request', error_description: 'redirect_uri is not registered for this client' };
   104→      return;
   105→    }
   106→
   107→    const requestedScopes = parseScopeParameter(scope);
   108→    const effectiveScopes = requestedScopes.length > 0 ? requestedScopes : DEFAULT_SCOPES;
   109→    const scopeValidation = validateRequestedScopes(effectiveScopes);
   110→
   111→    if (scopeValidation.unsupported.length > 0) {
   112→      ctx.logger.warn({
   113→        clientId,
   114→        redirectUri,
   115→        unsupportedScopes: scopeValidation.unsupported
   116→      }, 'Authorization request rejected due to unsupported scopes');
   117→      ctx.status = 400;
   118→      ctx.body = {
   119→        error: 'invalid_scope',
   120→        error_description: `Unsupported scopes requested: ${scopeValidation.unsupported.join(', ')}`
   121→      };
   122→      return;
   123→    }
   124→
   125→    const scopedRequest = buildScopeString(effectiveScopes);
   126→    // Use the Mittwald-specific scope format (see mittwald-scopes.ts for documentation)
   127→    const mittwaldScopeString = MITTWALD_SCOPE_STRING;
   128→
   129→    const internalState = randomUUID();
   130→
   131→    // Generate bridge's own PKCE pair for the Mittwald relationship
   132→    // Per FR-005: We store the verifier to use at token exchange, and send the challenge to Mittwald
   133→    const mittwaldCodeVerifier = generateCodeVerifier();
   134→    const mittwaldCodeChallenge = computeCodeChallenge(mittwaldCodeVerifier);
   135→
   136→    ctx.logger.debug({
   137→      clientState: state ? `${state.substring(0, 8)}...` : undefined,
   138→      internalState: `${internalState.substring(0, 8)}...`,
   139→      clientId,
   140→      mittwaldCodeVerifierLength: mittwaldCodeVerifier.length
   141→    }, 'Generated internal state and bridge PKCE pair for authorization');
   142→
   143→    try {
