    51→          'query'
    52→        ],
    53→        grant_types_supported: [
    54→          'authorization_code',
    55→          'refresh_token'
    56→        ],
    57→        code_challenge_methods_supported: [
    58→          'S256'
    59→        ],
    60→        subject_types_supported: [
